  ('judicial-cf446b4c-moex-00040', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於妨害家庭罪之敘述，依實務見解，下列何者錯誤？', '["和誘未滿16歲之已婚者，成立和誘有配偶之人罪", "和誘罪係保護監督權人對未成年人之監督權", "父母之一方得未滿7歲子女同意將其帶離，使脫離他方親權並阻隔他方探視監護，成立略誘未成年人罪", "略誘未滿16歲之人，以和誘論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00041', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法賭博罪的敘述，下列何者錯誤？', '["在公共場所或公眾得出入之場所賭博者，成立賭博罪", "意圖營利架設賭博網站供人賭博財物，亦成立供給賭博場所罪", "組頭以自有私人住宅作為簽賭處所，供不特定人前來簽賭，賭客亦成立賭博罪", "賭客透過網路以帳號密碼登入賭博網站，與網站經營者對賭財物，不成立賭博罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00042', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲為計程車司機，駕駛計程車時，因與車內乘客聊天，致超車時，不慎撞擊前方機車，致騎乘機車乙人車 倒地，乙跌倒時臉部正好撞到路邊小灌木，致右眼受傷，眼睛視力從1.2減至0.1，且永久無法恢復該眼視 力。甲之行為應如何論罪？', '["過失傷害罪", "過失傷害致重傷害罪", "過失重傷罪", "重傷罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00043', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於傷害罪章之罪，下列敘述何者正確？', '["我國刑法並無過失傷害罪", "聚眾鬥毆致人於死或重傷者，在場助勢之人不構成犯罪", "對於未滿18 歲之人，施以凌虐或以他法足以妨害其身心之健全或發育者，雖未有客觀可見之傷口，亦 構成犯罪", "激於義憤犯傷害罪者，其處罰較普通傷害罪為重"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
